__kernel void 
lud_diagonal(__global float *m, int matrix_dim, int offset)
{
  int i, j;
  __local float shadow[BLOCK_SIZE][BLOCK_SIZE];

  int array_offset = offset * matrix_dim + offset;
  int tid = get_local_id(0);

  for (i = 0; i < BLOCK_SIZE; i++) {
    shadow[i][tid] = m[array_offset + tid];
    array_offset += matrix_dim;
  }
  __syncthreads();

  for (i = 0; i < BLOCK_SIZE - 1; i++) {
    if (tid > i) {
      float val = shadow[tid][i];
      for (j = 0; j < i; j++) {
        val -= shadow[tid][j] * shadow[j][i];
      }
      shadow[tid][i] = val / shadow[i][i];
    }
    __syncthreads();

    if (tid > i) {
      float val = shadow[i + 1][tid];
      for (j = 0; j < i + 1; j++) {
        val -= shadow[i + 1][j] * shadow[j][tid];
      }
      shadow[i + 1][tid] = val;
    }
    __syncthreads();
  }

  array_offset = (offset + 1) * matrix_dim + offset;
  for (i = 1; i < BLOCK_SIZE; i++) {
    m[array_offset + tid] = shadow[i][tid];
    array_offset += matrix_dim;
  }
}

__kernel void
lud_perimeter(__global float *m, int matrix_dim, int offset)
{
