__kernel void
lud_internal(__global float *m, int matrix_dim, int offset)
{
  __local float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  __local float peri_col[BLOCK_SIZE][BLOCK_SIZE];

  int i;
  float sum;

  int global_row_id = offset + (get_group_id(1) + 1) * BLOCK_SIZE;
  int global_col_id = offset + (get_group_id(0) + 1) * BLOCK_SIZE;
  int local_x = get_local_id(0);
  int local_y = get_local_id(1);

  peri_row[local_y][local_x] = m[(offset + local_y) * matrix_dim + global_col_id + local_x];
  peri_col[local_y][local_x] = m[(global_row_id + local_y) * matrix_dim + offset + local_x];

  __syncthreads();

  sum = 0.0f;
  for (i = 0; i < BLOCK_SIZE; i++) {
    sum += peri_col[local_y][i] * peri_row[i][local_x];
  }
  m[(global_row_id + local_y) * matrix_dim + global_col_id + local_x] -= sum;
}
